


-- all 10 tables (500 rows each) and (5,000 Datas).
--  =====================================================================
BEGIN TRANSACTION;
CREATE TABLE players (
    player_id     SERIAL PRIMARY KEY,
    username      TEXT    NOT NULL UNIQUE,
    full_name     TEXT    NOT NULL,
    email         TEXT    NOT NULL UNIQUE,
    country       TEXT    NOT NULL,
    date_of_birth TEXT,
    gender        TEXT    CHECK(gender IN ('Male','Female','Other')),
    rank_tier     TEXT    CHECK(rank_tier IN ('Bronze','Silver','Gold','Platinum','Diamond','Master','Grandmaster')),
    total_wins    INTEGER NOT NULL DEFAULT 0,
    total_losses  INTEGER NOT NULL DEFAULT 0,
    earnings_usd  REAL    NOT NULL DEFAULT 0.0,
    is_active     INTEGER NOT NULL DEFAULT 1,
    joined_at     TEXT    DEFAULT CURRENT_TIMESTAMP
);


select * from players









CREATE TABLE teams (
    team_id       SERIAL PRIMARY KEY,
    team_name     TEXT    NOT NULL UNIQUE,
    tag           TEXT    NOT NULL UNIQUE,
    country       TEXT    NOT NULL,
    founded_year  INTEGER,
    coach_name    TEXT,
    manager_name  TEXT,
    total_wins    INTEGER NOT NULL DEFAULT 0,
    prize_pool_usd REAL   NOT NULL DEFAULT 0.0,
    is_active     INTEGER NOT NULL DEFAULT 1,
    logo_url      TEXT
);
CREATE TABLE games (
    game_id       SERIAL PRIMARY KEY,
    game_name     TEXT    NOT NULL UNIQUE,
    genre         TEXT    NOT NULL CHECK(genre IN ('FPS','MOBA','Battle Royale','RTS','Fighting','Sports','Card','MMO')),
    developer     TEXT    NOT NULL,
    publisher     TEXT    NOT NULL,
    platform      TEXT    NOT NULL,
    release_year  INTEGER,
    max_players   INTEGER NOT NULL DEFAULT 5,
    is_active     INTEGER NOT NULL DEFAULT 1,
    prize_pool_total_usd REAL NOT NULL DEFAULT 0.0
);
CREATE TABLE tournaments (
    tournament_id  SERIAL PRIMARY KEY,
    tournament_name TEXT   NOT NULL,
    game_id        INTEGER NOT NULL REFERENCES games(game_id),
    format         TEXT    NOT NULL CHECK(format IN ('Single Elimination','Double Elimination','Round Robin','Swiss','League')),
    start_date     TEXT    NOT NULL,
    end_date       TEXT,
    location       TEXT,
    is_online      INTEGER NOT NULL DEFAULT 1,
    prize_pool_usd REAL    NOT NULL DEFAULT 0.0,
    max_teams      INTEGER NOT NULL DEFAULT 16,
    status         TEXT    NOT NULL CHECK(status IN ('Upcoming','Ongoing','Completed','Cancelled')),
    organizer      TEXT
);
CREATE TABLE matches (
    match_id       SERIAL PRIMARY KEY,
    tournament_id  INTEGER NOT NULL REFERENCES tournaments(tournament_id),
    game_id        INTEGER NOT NULL REFERENCES games(game_id),
    team1_id       INTEGER NOT NULL REFERENCES teams(team_id),
    team2_id       INTEGER NOT NULL REFERENCES teams(team_id),
    round_name     TEXT    NOT NULL,
    scheduled_at   TEXT    NOT NULL,
    played_at      TEXT,
    status         TEXT    NOT NULL CHECK(status IN ('Scheduled','Live','Completed','Cancelled','Postponed')),
    map_played     TEXT,
    stream_url     TEXT,
    CHECK (team1_id != team2_id)
);
CREATE TABLE match_results (
    result_id      SERIAL PRIMARY KEY,
    match_id       INTEGER NOT NULL UNIQUE REFERENCES matches(match_id),
    winner_team_id INTEGER NOT NULL REFERENCES teams(team_id),
    loser_team_id  INTEGER NOT NULL REFERENCES teams(team_id),
    team1_score    INTEGER NOT NULL DEFAULT 0,
    team2_score    INTEGER NOT NULL DEFAULT 0,
    duration_mins  INTEGER,
    mvp_player_id  INTEGER REFERENCES players(player_id),
    highlights_url TEXT,
    recorded_at    TEXT    DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE rankings (
    ranking_id     SERIAL PRIMARY KEY,
    player_id      INTEGER NOT NULL REFERENCES players(player_id),
    game_id        INTEGER NOT NULL REFERENCES games(game_id),
    rank_position  INTEGER NOT NULL,
    rating_points  REAL    NOT NULL DEFAULT 0.0,
    wins           INTEGER NOT NULL DEFAULT 0,
    losses         INTEGER NOT NULL DEFAULT 0,
    win_rate       REAL    NOT NULL DEFAULT 0.0,
    kda_ratio      REAL,
    season         TEXT    NOT NULL DEFAULT '2024',
    updated_at     TEXT    DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(player_id, game_id, season)
);
CREATE TABLE sponsors (
    sponsor_id     SERIAL PRIMARY KEY,
    company_name   TEXT    NOT NULL UNIQUE,
    industry       TEXT    NOT NULL CHECK(industry IN ('Hardware','Software','Energy Drink','Apparel','Financial','Telecom','Food','Streaming','Peripherals','Auto')),
    country        TEXT    NOT NULL,
    contact_email  TEXT,
    website        TEXT,
    deal_amount_usd REAL   NOT NULL DEFAULT 0.0,
    contract_start TEXT,
    contract_end   TEXT,
    is_active      INTEGER NOT NULL DEFAULT 1,
    tier           TEXT    NOT NULL CHECK(tier IN ('Title','Gold','Silver','Bronze','Media'))
);
CREATE TABLE awards (
    award_id       SERIAL PRIMARY KEY,
    award_name     TEXT    NOT NULL,
    category       TEXT    NOT NULL CHECK(category IN ('MVP','Best Player','Best Team','Rookie','Clutch','Top Fragger','Best Support','Best IGL','Fan Favorite','Sportsmanship')),
    tournament_id  INTEGER REFERENCES tournaments(tournament_id),
    player_id      INTEGER REFERENCES players(player_id),
    team_id        INTEGER REFERENCES teams(team_id),
    game_id        INTEGER REFERENCES games(game_id),
    prize_usd      REAL    NOT NULL DEFAULT 0.0,
    awarded_on     TEXT    NOT NULL,
    description    TEXT
);
CREATE TABLE streaming_platforms (
    platform_id    SERIAL PRIMARY KEY,
    platform_name  TEXT    NOT NULL UNIQUE,
    base_url       TEXT    NOT NULL,
    country        TEXT    NOT NULL DEFAULT 'Global',
    language       TEXT    NOT NULL DEFAULT 'English',
    subscribers_m  REAL    NOT NULL DEFAULT 0.0,
    peak_viewers   INTEGER NOT NULL DEFAULT 0,
    revenue_usd_m  REAL    NOT NULL DEFAULT 0.0,
    tournament_id  INTEGER REFERENCES tournaments(tournament_id),
    broadcast_start TEXT,
    broadcast_end   TEXT,
    is_exclusive   INTEGER NOT NULL DEFAULT 0,
    is_active      INTEGER NOT NULL DEFAULT 1
);




