CREATE VIEW v_player_stats AS
SELECT p.player_id, p.username, p.country, p.rank_tier,
       p.total_wins, p.total_losses,
       ROUND(100.0*p.total_wins/(p.total_wins+p.total_losses+0.001),2) AS win_rate_pct,
       p.earnings_usd
FROM players p ORDER BY p.earnings_usd DESC;
CREATE VIEW v_tournament_summary AS
SELECT t.tournament_id, t.tournament_name, g.game_name,
       t.format, t.status, t.prize_pool_usd,
       COUNT(m.match_id) AS total_matches,
       t.start_date, t.end_date
FROM tournaments t
JOIN games g ON g.game_id = t.game_id
LEFT JOIN matches m ON m.tournament_id = t.tournament_id
GROUP BY t.tournament_id, t.tournament_name, g.game_name,
         t.format, t.status, t.prize_pool_usd, t.start_date, t.end_date;
CREATE VIEW v_top_teams AS
SELECT t.team_name, t.country, t.total_wins,
       t.prize_pool_usd,
       COUNT(mr.result_id) AS matches_won
FROM teams t
LEFT JOIN match_results mr ON mr.winner_team_id = t.team_id
GROUP BY t.team_id, t.team_name, t.country, t.total_wins, t.prize_pool_usd
ORDER BY t.prize_pool_usd DESC;
CREATE VIEW v_leaderboard AS
SELECT r.season, p.username, p.country, g.game_name,
       r.rank_position, r.rating_points, r.win_rate, r.kda_ratio
FROM rankings r
JOIN players p ON p.player_id = r.player_id
JOIN games   g ON g.game_id   = r.game_id
ORDER BY r.season DESC, r.rating_points DESC;
COMMIT;












-- 30_queries.........!?


-- 1. Top 10 highest-earning players
SELECT username, country, rank_tier, earnings_usd
FROM players
ORDER BY earnings_usd DESC
LIMIT 10;

-- 2. Players with a win rate above 60%, min 100 games played
SELECT username, total_wins, total_losses,
       ROUND((total_wins::numeric / (total_wins + total_losses)) * 100, 2) AS win_rate_pct
FROM players
WHERE (total_wins + total_losses) >= 100
  AND total_wins::numeric / (total_wins + total_losses) > 0.60
ORDER BY win_rate_pct DESC
LIMIT 15;

-- 3. Count of active vs inactive players by country (top 10 countries)
SELECT country,
       COUNT(*) FILTER (WHERE is_active = 1) AS active_players,
       COUNT(*) FILTER (WHERE is_active = 0) AS inactive_players
FROM players
GROUP BY country
ORDER BY active_players DESC
LIMIT 10;

-- 4. Average earnings per rank tier
SELECT rank_tier, ROUND(AVG(earnings_usd)::numeric, 2) AS avg_earnings, COUNT(*) AS player_count
FROM players
WHERE rank_tier IS NOT NULL
GROUP BY rank_tier
ORDER BY avg_earnings DESC;

-- 5. Teams with the highest total prize pool
SELECT team_name, tag, country, total_wins, prize_pool_usd
FROM teams
ORDER BY prize_pool_usd DESC
LIMIT 10;

-- 6. Number of teams founded per year
SELECT founded_year, COUNT(*) AS teams_founded
FROM teams
WHERE founded_year IS NOT NULL
GROUP BY founded_year
ORDER BY founded_year;

-- 7. Active teams vs inactive teams by country
SELECT country, is_active, COUNT(*) AS team_count
FROM teams
GROUP BY country, is_active
ORDER BY country, is_active;

-- 8. Games by genre with total prize pools
SELECT genre, COUNT(*) AS game_count, ROUND(SUM(prize_pool_total_usd)::numeric, 2) AS total_prize_pool
FROM games
GROUP BY genre
ORDER BY total_prize_pool DESC;

-- 9. Top 5 games by total prize pool
SELECT game_name, genre, developer, prize_pool_total_usd
FROM games
ORDER BY prize_pool_total_usd DESC
LIMIT 5;

-- 10. Tournaments by status, count and total prize pool
SELECT status, COUNT(*) AS tournament_count, ROUND(SUM(prize_pool_usd)::numeric, 2) AS total_prize
FROM tournaments
GROUP BY status
ORDER BY total_prize DESC;

-- 11. Tournaments happening in a given location (e.g. Berlin), with game name
SELECT tr.tournament_name, g.game_name, tr.start_date, tr.status, tr.prize_pool_usd
FROM tournaments tr
JOIN games g ON g.game_id = tr.game_id
WHERE tr.location = 'Berlin'
ORDER BY tr.start_date;

-- 12. Top organizers by number of tournaments run
SELECT organizer, COUNT(*) AS tournaments_run, ROUND(SUM(prize_pool_usd)::numeric,2) AS total_prize
FROM tournaments
WHERE organizer IS NOT NULL
GROUP BY organizer
ORDER BY tournaments_run DESC
LIMIT 10;

-- 13. Matches per status (Completed, Live, Scheduled, etc.)
SELECT status, COUNT(*) AS match_count
FROM matches
GROUP BY status
ORDER BY match_count DESC;

-- 14. Matches scheduled in a particular round (e.g. Grand Final), with team names
SELECT m.match_id, t1.team_name AS team1, t2.team_name AS team2,
       m.scheduled_at, m.status
FROM matches m
JOIN teams t1 ON t1.team_id = m.team1_id
JOIN teams t2 ON t2.team_id = m.team2_id
WHERE m.round_name = 'Grand Final'
ORDER BY m.scheduled_at
LIMIT 20;

-- 15. Number of matches played per tournament (top 10 busiest tournaments)
SELECT tr.tournament_name, COUNT(m.match_id) AS match_count
FROM tournaments tr
JOIN matches m ON m.tournament_id = tr.tournament_id
GROUP BY tr.tournament_id, tr.tournament_name
ORDER BY match_count DESC
LIMIT 10;

-- 16. Win/loss record per team, derived from match_results
SELECT t.team_name,
       COUNT(*) FILTER (WHERE mr.winner_team_id = t.team_id) AS wins,
       COUNT(*) FILTER (WHERE mr.loser_team_id = t.team_id) AS losses
FROM teams t
LEFT JOIN match_results mr
       ON t.team_id IN (mr.winner_team_id, mr.loser_team_id)
GROUP BY t.team_id, t.team_name
ORDER BY wins DESC
LIMIT 15;

-- 17. Average match duration (mins) per tournament format
SELECT tr.format, ROUND(AVG(mr.duration_mins)::numeric, 1) AS avg_duration_mins, COUNT(*) AS matches
FROM match_results mr
JOIN matches m ON m.match_id = mr.match_id
JOIN tournaments tr ON tr.tournament_id = m.tournament_id
GROUP BY tr.format
ORDER BY avg_duration_mins DESC;

-- 18. Players who were MVP in match_results most often
SELECT p.username, p.country, COUNT(*) AS mvp_count
FROM match_results mr
JOIN players p ON p.player_id = mr.mvp_player_id
GROUP BY p.player_id, p.username, p.country
ORDER BY mvp_count DESC
LIMIT 10;

-- 19. Closest matches (smallest score difference) in match_results
SELECT match_id, team1_score, team2_score,
       ABS(team1_score - team2_score) AS score_diff
FROM match_results
ORDER BY score_diff ASC, match_id
LIMIT 10;

-- 20. Top players in current rankings (season 2024), by rating points
SELECT p.username, g.game_name, r.rank_position, r.rating_points, r.win_rate
FROM rankings r
JOIN players p ON p.player_id = r.player_id
JOIN games g ON g.game_id = r.game_id
WHERE r.season = '2024'
ORDER BY r.rating_points DESC
LIMIT 15;

-- 21. Average KDA ratio per game, across all ranking seasons
SELECT g.game_name, ROUND(AVG(r.kda_ratio)::numeric, 2) AS avg_kda, COUNT(*) AS ranked_entries
FROM rankings r
JOIN games g ON g.game_id = r.game_id
WHERE r.kda_ratio IS NOT NULL
GROUP BY g.game_name
ORDER BY avg_kda DESC
LIMIT 10;

-- 22. Player rating progression across seasons (for players ranked in multiple seasons)
SELECT p.username, r.season, r.rating_points, r.rank_position
FROM rankings r
JOIN players p ON p.player_id = r.player_id
WHERE p.player_id IN (
    SELECT player_id FROM rankings GROUP BY player_id HAVING COUNT(DISTINCT season) > 1
)
ORDER BY p.username, r.season;

-- 23. Sponsorship deals by industry, total and average deal amount
SELECT industry, COUNT(*) AS deal_count,
       ROUND(SUM(deal_amount_usd)::numeric, 2) AS total_deal_amount,
       ROUND(AVG(deal_amount_usd)::numeric, 2) AS avg_deal_amount
FROM sponsors
GROUP BY industry
ORDER BY total_deal_amount DESC;

-- 24. Active sponsorship deals expiring within the next year (relative to a fixed reference date)
SELECT company_name, tier, deal_amount_usd, contract_end
FROM sponsors
WHERE is_active = 1
  AND contract_end::date BETWEEN DATE '2026-06-20' AND (DATE '2026-06-20' + INTERVAL '1 year')
ORDER BY contract_end::date;

-- 25. Top 3 sponsors by deal amount, within each tier
SELECT tier, company_name, deal_amount_usd, tier_rank
FROM (
    SELECT tier, company_name, deal_amount_usd,
           RANK() OVER (PARTITION BY tier ORDER BY deal_amount_usd DESC) AS tier_rank
    FROM sponsors
) ranked
WHERE tier_rank <= 3
ORDER BY tier, tier_rank;

-- 26. Award categories and how many were given, plus total prize money
SELECT category, COUNT(*) AS award_count, ROUND(SUM(prize_usd)::numeric, 2) AS total_prize
FROM awards
GROUP BY category
ORDER BY total_prize DESC;

-- 27. Players who won the most individual awards
SELECT p.username, COUNT(*) AS awards_won, ROUND(SUM(a.prize_usd)::numeric, 2) AS total_award_money
FROM awards a
JOIN players p ON p.player_id = a.player_id
GROUP BY p.player_id, p.username
ORDER BY awards_won DESC
LIMIT 10;

-- 28. Streaming platforms ranked by peak viewers for a given tournament
SELECT sp.platform_name, sp.country, sp.peak_viewers, sp.revenue_usd_m, tr.tournament_name
FROM streaming_platforms sp
JOIN tournaments tr ON tr.tournament_id = sp.tournament_id
ORDER BY sp.peak_viewers DESC
LIMIT 10;

-- 29. Total streaming revenue and average subscribers per platform country
SELECT country, COUNT(*) AS platform_count,
       ROUND(SUM(revenue_usd_m)::numeric, 2) AS total_revenue_m,
       ROUND(AVG(subscribers_m)::numeric, 2) AS avg_subscribers_m
FROM streaming_platforms
GROUP BY country
ORDER BY total_revenue_m DESC
LIMIT 10;

-- 30. Full tournament dashboard: tournament + game + match count + total streaming revenue (via the v_tournament_summary view)
SELECT vts.tournament_name, vts.game_name, vts.status, vts.total_matches,
       ROUND(COALESCE(SUM(sp.revenue_usd_m), 0)::numeric, 2) AS streaming_revenue_m
FROM v_tournament_summary vts
LEFT JOIN streaming_platforms sp ON sp.tournament_id = vts.tournament_id
GROUP BY vts.tournament_name, vts.game_name, vts.status, vts.total_matches
ORDER BY streaming_revenue_m DESC
LIMIT 10;









